import axios from 'axios';
import React, { useEffect, useState } from 'react';

export const Rasp = () => {
  const [rasps, setRasps] = useState([]);
  const [filters, setFilters] = useState({
    time: '',
    day: '',
    predmet: '',
    group: '',
    teacher: '',
    kurs: '',
    room: '',
  });

  useEffect(() => {
    // Construct the URL based on the selected filters
    const filterParams = Object.entries(filters)
      .filter(([key, value]) => value !== '')
      .map(([key, value]) => `${key}=${value}`)
      .join('&');

    const apiUrl = filterParams
      ? `http://localhost:5555/rasps?${filterParams}`
      : 'http://localhost:5555/rasps';

    axios
      .get(apiUrl)
      .then((response) => setRasps(response.data))
      .catch((err) => console.log(err));
  }, [filters]);

  const handleFilterChange = (field, value) => {
    setFilters((prevFilters) => ({ ...prevFilters, [field]: value }));
  };

  return (
    <div className="bg-white px-4 pt-3 pb-4 rounded-sm border border-gray-200 flex-1">
      <strong className="text-gray-700 font-medium">Расписания</strong>
      <div className="border-x border-gray-200 rounded-sm mt-3">
        <table className="w-full text-gray-700">
          <thead>
            <tr>
              <th>Время</th>
              <th>День</th>
              <th>Предмет</th>
              <th>Группа</th>
              <th>Преподаватель</th>
              <th>Курс</th>
              <th>Кабинет</th>
            </tr>
          </thead>
          <tbody>
            {rasps.map((item) => (
              <tr key={item._id}>
                <td>{item.time.time}</td>
                <td>{item.day.day}</td>
                <td>{item.predmet.predmet}</td>
                <td>{item.group.group_number}</td>
                <td>{item.teacher.teacher}</td>
                <td>{item.group.kurs}</td>
                <td>{item.room}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};
